  1586→// initSidecarScopes synthesizes Sidecar CRDs into objects called
  1587→// SidecarScope.  The SidecarScope object is a semi-processed view of the
  1588→// service registry, and config state associated with the sidecar CRD. The
  1589→// scope contains a set of inbound and outbound listeners, services/configs
  1590→// per listener, etc. The sidecar scopes are precomputed based on the
  1591→// Sidecar API objects in each namespace. If there is no sidecar api object
  1592→// for a namespace, a default sidecarscope is assigned to the namespace
  1593→// which enables connectivity to all services in the mesh.
  1594→//
  1595→// When proxies connect to Pilot, we identify the sidecar scope associated
  1596→// with the proxy and derive listeners/routes/clusters based on the sidecar
  1597→// scope.
  1598→func (ps *PushContext) initSidecarScopes(env *Environment) error {
  1599→	sidecarConfigs, err := env.List(gvk.Sidecar, NamespaceAll)
  1600→	if err != nil {
  1601→		return err
  1602→	}
  1603→
  1604→	sortConfigByCreationTime(sidecarConfigs)
  1605→
  1606→	sidecarConfigWithSelector := make([]config.Config, 0)
  1607→	sidecarConfigWithoutSelector := make([]config.Config, 0)
  1608→	sidecarsWithoutSelectorByNamespace := sets.New()
  1609→	for _, sidecarConfig := range sidecarConfigs {
  1610→		sidecar := sidecarConfig.Spec.(*networking.Sidecar)
  1611→		if sidecar.WorkloadSelector != nil {
  1612→			sidecarConfigWithSelector = append(sidecarConfigWithSelector, sidecarConfig)
  1613→		} else {
  1614→			sidecarsWithoutSelectorByNamespace.Insert(sidecarConfig.Namespace)
  1615→			sidecarConfigWithoutSelector = append(sidecarConfigWithoutSelector, sidecarConfig)
  1616→		}
  1617→	}
  1618→
  1619→	sidecarNum := len(sidecarConfigs)
  1620→	sidecarConfigs = make([]config.Config, 0, sidecarNum)
  1621→	// sidecars with selector take preference
  1622→	sidecarConfigs = append(sidecarConfigs, sidecarConfigWithSelector...)
  1623→	sidecarConfigs = append(sidecarConfigs, sidecarConfigWithoutSelector...)
  1624→
  1625→	// Hold reference root namespace's sidecar config
  1626→	// Root namespace can have only one sidecar config object
  1627→	// Currently we expect that it has no workloadSelectors
  1628→	var rootNSConfig *config.Config
  1629→	ps.sidecarIndex.sidecarsByNamespace = make(map[string][]*SidecarScope, sidecarNum)
  1630→	for i, sidecarConfig := range sidecarConfigs {
  1631→		ps.sidecarIndex.sidecarsByNamespace[sidecarConfig.Namespace] = append(ps.sidecarIndex.sidecarsByNamespace[sidecarConfig.Namespace],
  1632→			ConvertToSidecarScope(ps, &sidecarConfig, sidecarConfig.Namespace))
  1633→		if rootNSConfig == nil && sidecarConfig.Namespace == ps.Mesh.RootNamespace &&
  1634→			sidecarConfig.Spec.(*networking.Sidecar).WorkloadSelector == nil {
  1635→			rootNSConfig = &sidecarConfigs[i]
  1636→		}
  1637→	}
  1638→	ps.sidecarIndex.rootConfig = rootNSConfig
  1639→
  1640→	return nil
  1641→}
