  1668→// SetDestinationRules is updates internal structures using a set of configs.
  1669→// Split out of DestinationRule expensive conversions, computed once per push.
  1670→// This also allows tests to inject a config without having the mock.
  1671→// This will not work properly for Sidecars, which will precompute their destination rules on init
  1672→func (ps *PushContext) SetDestinationRules(configs []config.Config) {
  1673→	// Sort by time first. So if two destination rule have top level traffic policies
  1674→	// we take the first one.
  1675→	sortConfigByCreationTime(configs)
  1676→	namespaceLocalDestRules := make(map[string]*consolidatedDestRules)
  1677→	exportedDestRulesByNamespace := make(map[string]*consolidatedDestRules)
  1678→	rootNamespaceLocalDestRules := newProcessedDestRules()
  1679→	inheritedConfigs := make(map[string]*config.Config)
  1680→
  1681→	for i := range configs {
  1682→		rule := configs[i].Spec.(*networking.DestinationRule)
  1683→
  1684→		if features.EnableDestinationRuleInheritance && rule.Host == "" {
  1685→			if t, ok := inheritedConfigs[configs[i].Namespace]; ok {
  1686→				log.Warnf(
  1687→					"Namespace/mesh-level DestinationRule is already defined for %q at time %v. Ignore %q which was created at time %v",
  1688→					configs[i].Namespace, t.CreationTimestamp, configs[i].Name, configs[i].CreationTimestamp)
  1689→				continue
  1690→			}
  1691→			inheritedConfigs[configs[i].Namespace] = &configs[i]
  1692→		}
  1693→
  1694→		rule.Host = string(ResolveShortnameToFQDN(rule.Host, configs[i].Meta))
  1695→		exportToMap := make(map[visibility.Instance]bool)
  1696→
  1697→		// destination rules with workloadSelector should not be exported to other namespaces
  1698→		if rule.GetWorkloadSelector() == nil {
  1699→			for _, e := range rule.ExportTo {
  1700→				exportToMap[visibility.Instance(e)] = true
  1701→			}
  1702→		}
  1703→
  1704→		// add only if the dest rule is exported with . or * or explicit exportTo containing this namespace
  1705→		// The global exportTo doesn't matter here (its either . or * - both of which are applicable here)
  1706→		if len(exportToMap) == 0 || exportToMap[visibility.Public] || exportToMap[visibility.Private] ||
  1707→			exportToMap[visibility.Instance(configs[i].Namespace)] {
  1708→			// Store in an index for the config's namespace
  1709→			// a proxy from this namespace will first look here for the destination rule for a given service
  1710→			// This pool consists of both public/private destination rules.
  1711→			if _, exist := namespaceLocalDestRules[configs[i].Namespace]; !exist {
  1712→				namespaceLocalDestRules[configs[i].Namespace] = newProcessedDestRules()
  1713→			}
  1714→			// Merge this destination rule with any public/private dest rules for same host in the same namespace
  1715→			// If there are no duplicates, the dest rule will be added to the list
  1716→			ps.mergeDestinationRule(namespaceLocalDestRules[configs[i].Namespace], configs[i], exportToMap)
  1717→		}
  1718→
  1719→		isPrivateOnly := false
  1720→		// No exportTo in destinationRule. Use the global default
  1721→		// We only honor . and *
  1722→		if len(rule.ExportTo) == 0 && ps.exportToDefaults.destinationRule[visibility.Private] {
  1723→			isPrivateOnly = true
  1724→		} else if len(rule.ExportTo) == 1 && (exportToMap[visibility.Private]) {
  1725→			isPrivateOnly = true
  1726→		}
  1727→
  1728→		// If destination rule has a workloadSelector set, visibility should be private.
  1729→		if rule.GetWorkloadSelector() != nil {
  1730→			isPrivateOnly = true
  1731→		}
  1732→
  1733→		if !isPrivateOnly {
  1734→			if _, exist := exportedDestRulesByNamespace[configs[i].Namespace]; !exist {
  1735→				exportedDestRulesByNamespace[configs[i].Namespace] = newProcessedDestRules()
  1736→			}
  1737→			// Merge this destination rule with any other exported dest rule for the same host in the same namespace
  1738→			// If there are no duplicates, the dest rule will be added to the list
  1739→			ps.mergeDestinationRule(exportedDestRulesByNamespace[configs[i].Namespace], configs[i], exportToMap)
  1740→		} else if configs[i].Namespace == ps.Mesh.RootNamespace {
  1741→			// Keep track of private root namespace destination rules
  1742→			ps.mergeDestinationRule(rootNamespaceLocalDestRules, configs[i], exportToMap)
  1743→		}
  1744→	}
  1745→
  1746→	// precompute DestinationRules with inherited fields
  1747→	if features.EnableDestinationRuleInheritance {
  1748→		globalRule := inheritedConfigs[ps.Mesh.RootNamespace]
  1749→		for ns := range namespaceLocalDestRules {
  1750→			nsRule := inheritedConfigs[ns]
  1751→			inheritedRule := ps.inheritDestinationRule(globalRule, nsRule)
  1752→			for hostname, cfgList := range namespaceLocalDestRules[ns].destRules {
  1753→				for i, cfg := range cfgList {
  1754→					namespaceLocalDestRules[ns].destRules[hostname][i] = ps.inheritDestinationRule(inheritedRule, cfg)
  1755→				}
  1756→			}
  1757→			// update namespace rule after it has been merged with mesh rule
  1758→			inheritedConfigs[ns] = inheritedRule
  1759→		}
  1760→		// can't precalculate exportedDestRulesByNamespace since we don't know all the client namespaces in advance
  1761→		// inheritance is performed in getExportedDestinationRuleFromNamespace
  1762→	}
  1763→
  1764→	ps.destinationRuleIndex.namespaceLocal = namespaceLocalDestRules
  1765→	ps.destinationRuleIndex.exportedByNamespace = exportedDestRulesByNamespace
  1766→	ps.destinationRuleIndex.rootNamespaceLocal = rootNamespaceLocalDestRules
  1767→	ps.destinationRuleIndex.inheritedByNamespace = inheritedConfigs
  1768→}
