  1942→// if there is a workload selector, check for matching workload labels
  1943→func (ps *PushContext) getMatchedEnvoyFilters(proxy *Proxy, namespaces string) []*EnvoyFilterWrapper {
  1944→	matchedEnvoyFilters := make([]*EnvoyFilterWrapper, 0)
  1945→	for _, efw := range ps.envoyFiltersByNamespace[namespaces] {
