  2037→		} else if gw.GetSelector() == nil {
  2038→			// no selector. Applies to all workloads asking for the gateway
  2039→			gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, true, proxy.ServiceInstances})
  2040→		} else {
  2041→			gatewaySelector := labels.Instance(gw.GetSelector())
  2042→			var workloadLabels labels.Collection
  2043→			// This should never happen except in tests.
  2044→			if proxy.Metadata != nil && len(proxy.Metadata.Labels) > 0 {
  2045→				workloadLabels = labels.Collection{proxy.Metadata.Labels}
  2046→			}
  2047→			if workloadLabels.IsSupersetOf(gatewaySelector) {
  2048→				gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, true, proxy.ServiceInstances})
  2049→			}
  2050→		}
  2051→	}
  2052→
  2053→	if len(gatewayInstances) == 0 {
  2054→		return nil
  2055→	}
  2056→
  2057→	return MergeGateways(gatewayInstances, proxy, ps)
  2058→}
