  2137→func instancesEmpty(m map[int][]*ServiceInstance) bool {
  2138→	for _, instances := range m {
  2139→		if len(instances) > 0 {
  2140→			return false
  2141→		}
  2142→	}
  2143→	return true
  2144→}
