    23→// configKindAffectedProxyTypes contains known config types which may affect certain node types.
    24→var configKindAffectedProxyTypes = map[config.GroupVersionKind][]model.NodeType{
    25→	gvk.Gateway: {model.Router},
    26→	gvk.Secret:  {model.Router},
    27→	gvk.Sidecar: {model.SidecarProxy},
    28→}
