   656→// handleWorkloadHealthcheck processes HealthInformation type Url.
   657→func (s *DiscoveryServer) handleWorkloadHealthcheck(proxy *model.Proxy, req *discovery.DiscoveryRequest) {
   658→	if features.WorkloadEntryHealthChecks {
   659→		event := workloadentry.HealthEvent{}
   660→		event.Healthy = req.ErrorDetail == nil
   661→		if !event.Healthy {
   662→			event.Message = req.ErrorDetail.Message
   663→		}
   664→		s.WorkloadEntryController.QueueWorkloadEntryHealth(proxy, event)
   665→	}
   666→}
