   727→func reportAllEvents(s DistributionStatusCache, id, version string, ignored sets.Set) {
   728→	if s == nil {
   729→		return
   730→	}
   731→	// this version of the config will never be distributed to this envoy because it is not a relevant diff.
   732→	// inform distribution status reporter that this connection has been updated, because it effectively has
   733→	for distributionType := range AllEventTypes {
   734→		if ignored.Contains(distributionType) {
   735→			// Skip this type
   736→			continue
   737→		}
   738→		s.RegisterEvent(id, distributionType, version)
   739→	}
   740→}
